"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[1226],{16055:(e,t,a)=>{a.r(t),a.d(t,{data:()=>i});const i={key:"v-f3d2e542",path:"/git-tutorial/internal.html",title:"内部实现",lang:"zh-CN",frontmatter:{summary:"内部实现 .git 目录 版本管理的所有信息，保存在项目的.git目录之中。如果没有这个目录，Git 就会认为这个仓库没有建立版本管理，必须进行初始化。git init命令的主要作用，就是建立.git目录。 .git/config文件保存仓库的设置。 .git/HEAD文件保存当前工作分支的引用。 .git/hooks目录保存各种事件挂钩的脚本。 .git/",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/git-tutorial/internal.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"内部实现"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:".git 目录",slug:"git-目录",children:[]},{level:2,title:"哈希签名",slug:"哈希签名",children:[]},{level:2,title:"git add 命令",slug:"git-add-命令",children:[]},{level:2,title:"git commit 命令",slug:"git-commit-命令",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:1.17,words:352},filePathRelative:"git-tutorial/internal.md"}},87323:(e,t,a)=>{a.r(t),a.d(t,{default:()=>n});const i=(0,a(66252).uE)('<h1 id="内部实现" tabindex="-1"><a class="header-anchor" href="#内部实现" aria-hidden="true">#</a> 内部实现</h1><h2 id="git-目录" tabindex="-1"><a class="header-anchor" href="#git-目录" aria-hidden="true">#</a> .git 目录</h2><p>版本管理的所有信息，保存在项目的<code>.git</code>目录之中。如果没有这个目录，Git 就会认为这个仓库没有建立版本管理，必须进行初始化。<code>git init</code>命令的主要作用，就是建立<code>.git</code>目录。</p><p><code>.git/config</code>文件保存仓库的设置。</p><p><code>.git/HEAD</code>文件保存当前工作分支的引用。</p><p><code>.git/hooks</code>目录保存各种事件挂钩的脚本。</p><p><code>.git/objects</code>目录保存文件的内容，格式是二进制<code>blob</code>。</p><h2 id="哈希签名" tabindex="-1"><a class="header-anchor" href="#哈希签名" aria-hidden="true">#</a> 哈希签名</h2><p>每次提交的时候，每个文件、每个树节点（目录）和提交本身，都会生成一个40个字符长的 SHA-1 哈希。</p><p>哈希作为文件名，文件本身保留在<code>.git/objects</code>目录之中。</p><h2 id="git-add-命令" tabindex="-1"><a class="header-anchor" href="#git-add-命令" aria-hidden="true">#</a> git add 命令</h2><p><code>git add</code>会将变动的文件写入<code>.git/objects</code>目录。它内部调用的是<code>git hash-object</code>命令,该命令会计算 SHA-1 哈希，并将 blob 文件放入<code>.git/objects</code>目录。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">git</span> hash-object -w myfile.txt\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>git cat-file</code>命令可以查看 blob 格式对应的原始文件内容。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">git</span> cat-file -p e69de29bb2d1d6434b8b29ae775ad8c2e48c5391\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="git-commit-命令" tabindex="-1"><a class="header-anchor" href="#git-commit-命令" aria-hidden="true">#</a> git commit 命令</h2><p><code>git commit</code>命令用于有变动的、并已提交到<code>.git/objects</code>的文件写入历史。</p><p><code>git write-tree</code>为当前仓库创建树节点。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">git</span> write-tree\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>git commit-tree</code>命令将指定的树节点写入历史。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ echo“first commit”<span class="token operator">|</span> <span class="token function">git</span> commit-tree <span class="token punctuation">\\</span> 6e9432aeedbad83fbffb7f8aae4a5d1ab50b7fdf\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div>',21),d={},n=(0,a(83744).Z)(d,[["render",function(e,t){return i}]])},83744:(e,t)=>{t.Z=(e,t)=>{const a=e.__vccOpts||e;for(const[e,i]of t)a[e]=i;return a}}}]);